import React, { useState } from "react";
import axios from "axios";
import Api from "../api/Api";
import { useLocation, useNavigate } from "react-router-dom";

const Login = () => {
  const location = useLocation();
  const navigate = useNavigate();

  const mobile = location.state?.mobile || "";

  const [otp, setOtp] = useState("");

  const handleVerify = async (e) => {
    e.preventDefault();

    try {
      const res = await axios.post(Api.verify_otp, {
        mobile,
        otp,
      });

      alert(res.data.message);

    } catch (err) {
      alert(err.response?.data?.message || "OTP verification failed");
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 flex items-center justify-center px-4">

      <div className="bg-white shadow-lg rounded-xl p-8 w-full max-w-md">

        {/* IMAGE (same as signup) */}
        <div className="flex justify-center mb-4">
          <img
            src="garbageVehicle.jpeg"
            alt="Garbage Vehicle"
            className="w-24 h-24"
          />
        </div>

        {/* HEADING */}
        <h1 className="text-3xl font-bold text-center text-green-700">
          GarbagePickUpVehicle
        </h1>

        <p className="text-center text-gray-500 mt-2 mb-6">
          OTP Verification
        </p>

        {/* OTP FORM */}
        <form onSubmit={handleVerify} className="space-y-4">

          <div>
            <label className="block text-sm font-medium mb-1">
              Enter OTP
            </label>

            <input
              type="text"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
              placeholder="Enter OTP"
              className="w-full border rounded-lg px-4 py-2 text-center tracking-widest focus:outline-none focus:ring-2 focus:ring-green-500"
              required
            />
          </div>

          <button
            type="submit"
            className="w-full bg-green-600 text-white py-2 rounded-lg font-semibold hover:bg-green-700 transition"
          >
            Verify OTP
          </button>

        </form>

      </div>
    </div>
  );
};

export default Login;
